import json
import os
import re

def task_func(
    file_path,
    attribute,
    INPUT_JSON={
        "type": "object",
        "properties": {
            "name": {"type": str},  
            "age": {"type": int},   
            "email": {"type": str}  
        },
        "required": ["name", "age", "email"]
    },
    EMAIL_REGEX=r"^[a-z0-9]+[\._]?[a-z0-9]+[@]\w+[.]\w{2,3}$"
):
    if not os.path.exists(file_path):
        raise ValueError("File does not exist")

    with open(file_path, 'r') as file:
        data = json.load(file)

    for field in INPUT_JSON["required"]:
        if field not in data:
            raise ValueError(f"Missing required attribute: {field}")

    for field, field_type in INPUT_JSON["properties"].items():
        if field in data and not isinstance(data[field], field_type["type"]):
            raise ValueError(f"Type mismatch for attribute {field}: expected {field_type['type'].__name__}, got {type(data[field]).__name__}")

    if "email" in data and not re.match(EMAIL_REGEX, data["email"]):
        raise ValueError("Invalid email format")

    if attribute not in data:
        raise ValueError(f"Attribute {attribute} not found in JSON data")

    return data[attribute]

