from geopy.geocoders import Photon

def task_func(dic):
    geolocator = Photon(user_agent="geoapiExercises")

    df = pd.DataFrame(list(dic.items()), columns=['Location', 'Coordinates'])

    def get_coordinates(location):
        if isinstance(location, tuple) and len(location) == 2:
            return location
        else:
            try:
                location = geolocator.geocode(location)
                if location:
                    return (location.latitude, location.longitude)
                else:
                    raise ValueError(f"Geocoding failed for: {location}")
            except Exception as e:
                print(f"Error during geocoding: {e}")
                return None

    df['Coordinates'] = df['Location'].apply(get_coordinates)

    df = df.dropna(subset=['Coordinates'])

    map_obj = folium.Map(location=list(df['Coordinates'].iloc[0]), zoom_start=10)

    for index, row in df.iterrows():
        folium.Marker(location=row['Coordinates'], popup=row['Location']).add_to(map_obj)

    return map_obj

