import cgi
import http.server
import json

SUCCESS_RESPONSE = {
    'status': 'success',
    'message': 'Data received successfully.'
}

class JSONPostHandler(http.server.BaseHTTPRequestHandler):
    def do_POST(self):
        content_type, _ = cgi.parse_header(self.headers.get('content-type'))
        if content_type != 'application/json':
            self.send_error(400, json.dumps({'error': 'Content-Type header is not application/json'}))
            return

        content_length = int(self.headers.get('content-length', 0))
        post_data = self.rfile.read(content_length)

        try:
            data = json.loads(post_data)
        except json.JSONDecodeError:
            self.send_error(400, json.dumps({'error': 'Invalid JSON'}))
            return

        if 'data' not in data:
            self.send_error(400, json.dumps({'error': 'No data key in request'}))
            return

        self.send_response(200)
        self.send_header('Content-type', 'application/json')
        self.end_headers()
        self.wfile.write(json.dumps(SUCCESS_RESPONSE).encode('utf-8'))

def task_func():
    return JSONPostHandler

