        doc = Document(file_path)
        return '\n'.join([para.text for para in doc.paragraphs])
    elif file_extension == '.xlsx':
        df = pd.read_excel(file_path)
        return df.to_csv(index=False)
    elif file_extension == '.csv':
        df = pd.read_csv(file_path)
        return df.to_csv(index=False)

