from PIL import Image
import pytesseract

IMAGE_PATH = "image.png"

def task_func(filename=IMAGE_PATH, from_encoding="cp1251", to_encoding="utf8"):
    try:
        # Attempt to extract text from the image using OCR
        text = pytesseract.image_to_string(Image.open(filename))
        if text:
            # Convert the extracted text encoding
            try:
                text = text.encode(from_encoding).decode(to_encoding)
                return text
            except (UnicodeDecodeError, LookupError) as e:
                raise ValueError("UnicodeDecodeError or LookupError during text encoding conversion") from e
    except Exception as e:
        print(f"OCR failed with error: {e}")

    try:
        # If OCR fails, attempt to extract text from the image comment
        with Image.open(filename) as img:
            comment = img.info.get('comment', '')
            if comment:
                # Convert the comment encoding
                try:
                    comment = comment.encode(from_encoding).decode(to_encoding)
                    return comment
                except (UnicodeDecodeError, LookupError) as e:
                    raise ValueError("UnicodeDecodeError or LookupError during comment encoding conversion") from e
    except Exception as e:
        print(f"Comment processing failed with error: {e}")

    # If both OCR and comment processing fail, return an empty string
    return ""

