LOGFILE_PATH = "logfile.log"

def task_func(interval, duration):
    if interval <= 0 or duration <= 0:
        raise ValueError("Both 'interval' and 'duration' must be greater than zero.")

    start_time = time.time()
    end_time = start_time + duration
    cpu_usage_data = []

    while time.time() < end_time:
        timestamp = time.strftime("%Y-%m-%d %H:%M:%S", time.localtime())
        cpu_usage = get_cpu_usage()
        cpu_usage_data.append({"timestamp": timestamp, "cpu_usage": cpu_usage})
        time.sleep(interval)

    try:
        with open(LOGFILE_PATH, 'w') as logfile:
            json.dump(cpu_usage_data, logfile, indent=4)
        return LOGFILE_PATH
    except IOError as e:
        print(f"Failed to write to log file: {e}")
        return None

def get_cpu_usage():
    if platform.system() == "Windows":
        return get_cpu_usage_windows()
    else:
        return get_cpu_usage_unix()

def get_cpu_usage_windows():
    result = subprocess.run(['wmic', 'cpu', 'get', 'loadpercentage'], capture_output=True, text=True)
    if result.returncode == 0:
        return int(result.stdout.strip().split('\n')[1])
    else:
        raise RuntimeError("Failed to retrieve CPU usage on Windows.")

def get_cpu_usage_unix():
    result = subprocess.run(['top', '-bn1', '-i', '0.1'], capture_output=True, text=True)
    if result.returncode == 0:
        lines = result.stdout.split('\n')
        for line in lines:
            if "%Cpu(s)" in line:
                cpu_usage = line.split(',')[0].split()[1]
                return float(cpu_usage)
    raise RuntimeError("Failed to retrieve CPU usage on Unix/Linux.")

