import psutil
import time
def task_func(process_name: str) -> str:
    # Function to check if a process is running by name
    def is_process_running(process_name):
        for proc in psutil.process_iter(['name']):
            try:
                if proc.info['name'] == process_name:
                    return True
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
        return False

    # Check if the process is running
    if not is_process_running(process_name):
        # Start the process
        subprocess.Popen(process_name)
        return f"Process not found. Starting {process_name}."
    else:
        # Find and terminate the process
        for proc in psutil.process_iter(['name', 'pid']):
            try:
                if proc.info['name'] == process_name:
                    proc.terminate()
                    proc.wait()  # Wait for the process to terminate
                    time.sleep(1)  # Wait for a second to ensure the process is terminated
                    # Restart the process
                    subprocess.Popen(process_name)
                    return f"Process found. Restarting {process_name}."
            except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
                pass
        return f"Failed to restart {process_name}."

