import cgi
import http.server
import json

SUCCESS_RESPONSE = {
    'status': 'success',
    'message': 'Data received successfully.'
}

class JSONPostHandler(http.server.BaseHTTPRequestHandler):
    def do_POST(self):
        self._handle_post_request()

    def _handle_post_request(self):
        if not self._is_valid_content_type():
            self._send_error_response(400, {'error': 'Content-Type header is not application/json'})
            return

        data = self._parse_json_data()
        if isinstance(data, dict) and 'data' in data:
            self._send_success_response()
        else:
            self._send_error_response(400, {'error': 'No data key in request'})

    def _is_valid_content_type(self):
        content_type, _ = cgi.parse_header(self.headers.get('content-type'))
        return content_type == 'application/json'

    def _parse_json_data(self):
        try:
            content_length = int(self.headers.get('content-length', 0))
            post_data = self.rfile.read(content_length)
            return json.loads(post_data)
        except (json.JSONDecodeError, ValueError):
            self._send_error_response(400, {'error': 'Invalid JSON'})
            return None

    def _send_success_response(self):
        self.send_response(200)
        self._set_headers()
        self.wfile.write(json.dumps(SUCCESS_RESPONSE).encode('utf-8'))

    def _send_error_response(self, status_code, error_message):
        self.send_response(status_code)
        self._set_headers()
        self.wfile.write(json.dumps(error_message).encode('utf-8'))

    def _set_headers(self):
        self.send_header('Content-type', 'application/json')
        self.end_headers()

def task_func():
    return JSONPostHandler

