def calculate_means(data_list):
    if not data_list:
        return pd.DataFrame(columns=['Mean Value'])

    max_length = max(len(tup) for tup in data_list)
    sums = [0] * max_length
    counts = [0] * max_length

    for tup in data_list:
        for i, value in enumerate(tup):
            if isinstance(value, (int, float)):
                sums[i] += value
                counts[i] += 1

    means = [sums[i] / counts[i] if counts[i] > 0 else np.nan for i in range(max_length)]
    df = pd.DataFrame({'Mean Value': means}, index=[f'Position {i}' for i in range(max_length)])

    return df

