import pandas as pd
from scipy.stats import chi2_contingency

def task_func(data, col1, col2):
    # Validate DataFrame and columns
    if data.empty:
        raise ValueError("The 'data' DataFrame is empty.")

    missing_cols = [col for col in [col1, col2] if col not in data.columns]
    if missing_cols:
        raise ValueError(f"One or both of the specified columns ({', '.join(missing_cols)}) are not in the DataFrame.")

    # Validate categorical data
    for col in [col1, col2]:
        dtype = data[col].dtype
        if not (pd.api.types.is_categorical_dtype(dtype) or pd.api.types.is_object_dtype(dtype)):
            raise TypeError(f"The column '{col}' does not contain categorical data.")

    # Validate multiple categories
    for col in [col1, col2]:
        unique_count = len(data[col].unique())
        if unique_count < 2:
            raise ValueError(f"The column '{col}' does not have multiple categories.")

    # Perform chi-square test of independence
    contingency_table = pd.crosstab(data[col1], data[col2])
    chi2, p_value, _, _ = chi2_contingency(contingency_table)

    return p_value

