import zipfile
from pathlib import Path

def task_func(source_dir: str, target_dir: str, archive_name: str = 'archive.zip') -> str:
    # Ensure the target directory exists
    target_path = Path(target_dir).resolve()
    target_path.mkdir(parents=True, exist_ok=True)

    # Define the full path for the archive
    archive_path = target_path / archive_name

    # Create a new zip file and add processed files
    with zipfile.ZipFile(archive_path, 'w', zipfile.ZIP_DEFLATED) as archive:
        for root, _, files in os.walk(source_dir):
            for file in files:
                if file.endswith('_processed'):
                    file_path = Path(root) / file
                    archive.write(file_path, file_path.relative_to(source_dir))

    return str(archive_path)

from typing import List, Union
import numpy as np
import scipy.fft

def task_func(data: List[Union[int, str]], repetitions: int = 1) -> dict:
    if not data or repetitions <= 0:
        return {'mode': np.array([]), 'count': np.array([])}

    repeated_data = data * repetitions

    unique_elements, counts = np.unique(repeated_data, return_counts=True)
    max_count = np.max(counts)
    modes = unique_elements[counts == max_count]
    modes_sorted = np.sort(modes)

    fft_result = scipy.fft.fft(repeated_data)

    return {
        'mode': modes_sorted,
        'count': np.full_like(modes_sorted, max_count)
    }

import pandas as pd
import numpy as np
from statsmodels.tsa.seasonal import seasonal_decompose

def generate_sales_time_series(start_date='2016-01-01', periods=24, freq='M'):
    """Generate a random sales time series."""
    date_range = pd.date_range(start=start_date, periods=periods, freq=freq)
    np.random.seed(0)  # For reproducibility
    sales_data = np.random.randint(100, 1000, size=periods)
    return pd.Series(sales_data, index=date_range)

def decompose_time_series(time_series, model='additive'):
    """Decompose a time series into trend, seasonal, and residual components."""
    decomposition = seasonal_decompose(time_series, model=model)
    return {
        'trend': decomposition.trend,
        'seasonal': decomposition.seasonal,
        'residual': decomposition.resid
    }

def task_func(start_date='2016-01-01', periods=24, freq='M', model='additive'):
    """Generate a sales time series and decompose it."""
    sales_series = generate_sales_time_series(start_date, periods, freq)
    return decompose_time_series(sales_series, model)

import os
import re
from pathlib import Path
def task_func(dir_path: str, predicates: list) -> dict:
    # Deduplicate predicates
    predicates = list(set(predicates))

    # Check if predicates are valid
    if not predicates:
        raise ValueError("No valid predicates are provided.")

    # Check if the directory exists and is a directory
    if not os.path.exists(dir_path) or not os.path.isdir(dir_path):
        raise FileNotFoundError("The specified directory does not exist or is not a directory.")

    # Initialize the result dictionary
    result = {}

    # Iterate over each item in the directory
    for item in os.listdir(dir_path):
        # Evaluate each predicate against the item name
        item_result = []
        for predicate in predicates:
            if isinstance(predicate, str):
                # Check if the item name matches the string predicate
                item_result.append(item == predicate)
            elif isinstance(predicate, re.Pattern):
                # Check if the item name matches the regex predicate
                item_result.append(bool(predicate.match(item)))
            else:
                raise ValueError("Invalid predicate type. Only strings and regex patterns are allowed.")

        # Store the results in the dictionary
        result[item] = item_result

    return result

