from PIL import Image
import pytesseract

IMAGE_PATH = "image.png"

def task_func(filename=IMAGE_PATH, from_encoding="cp1251", to_encoding="utf8"):
    def convert_text(text):
        try:
            return text.encode(from_encoding).decode(to_encoding)
        except (UnicodeDecodeError, LookupError) as e:
            raise ValueError(f"Encoding conversion error: {e}") from e

    try:
        # Attempt to extract text from the image using OCR
        extracted_text = pytesseract.image_to_string(Image.open(filename))
        if extracted_text.strip():
            return convert_text(extracted_text)
    except Exception as e:
        print(f"OCR failed with error: {e}")

    try:
        # Attempt to extract text from the image comment
        with Image.open(filename) as img:
            comment = img.info.get('comment', '')
            if comment:
                return convert_text(comment)
    except Exception as e:
        print(f"Comment extraction failed with error: {e}")

    # If both OCR and comment processing fail, return an empty string
    return ""

import json
import requests
import chardet
API_URL = "http://api.example.com/data"
def task_func(url=API_URL, from_encoding=None, to_encoding="utf8"):
    try:
        # Make an HTTP GET request with a 5-second timeout
        response = requests.get(url, timeout=5)
        response.raise_for_status()  # Raise an error for bad responses

        # Get the raw bytes content
        raw_content = response.content

        # Handle empty content
        if not raw_content:
            return {}

        # Detect encoding if not provided
        if not from_encoding:
            detection = chardet.detect(raw_content)
            from_encoding = detection.get('encoding')
            if not from_encoding:
                raise ValueError("Unable to detect encoding for non-empty content")

        # Decode the content
        decoded_content = raw_content.decode(from_encoding)

        # Re-encode the content
        re_encoded_content = decoded_content.encode(to_encoding)

        # Parse the JSON
        json_data = json.loads(re_encoded_content.decode(to_encoding))

        return json_data

    except requests.exceptions.RequestException as e:
        print(f"Request failed: {e}")
        return {}
    except json.JSONDecodeError as e:
        print(f"JSON decoding failed: {e}")
        return {}
    except ValueError as e:
        print(f"Value error: {e}")
        raise

import subprocess
import time
import json
import platform

LOGFILE_PATH = "logfile.log"

def task_func(interval, duration):
    if interval <= 0 or duration <= 0:
        raise ValueError("Both 'interval' and 'duration' must be greater than zero.")

    start_time = time.time()
    end_time = start_time + duration
    cpu_usage_data = []

    while time.time() < end_time:
        timestamp = time.strftime("%Y-%m-%d %H:%M:%S", time.localtime())
        cpu_usage = get_cpu_usage()
        cpu_usage_data.append({"timestamp": timestamp, "cpu_usage": cpu_usage})
        time.sleep(interval)

    try:
        with open(LOGFILE_PATH, 'w') as logfile:
            json.dump(cpu_usage_data, logfile, indent=4)
        return LOGFILE_PATH
    except IOError as e:
        raise RuntimeError("Failed to write CPU usage data to file.") from e

def get_cpu_usage():
    if platform.system() == "Windows":
        return get_cpu_usage_windows()
    else:
        return get_cpu_usage_unix()

def get_cpu_usage_windows():
    result = subprocess.run(['wmic', 'cpu', 'get', 'loadpercentage'], capture_output=True, text=True)
    if result.returncode == 0:
        try:
            return int(result.stdout.strip().split('\n')[1])
        except (ValueError, IndexError) as e:
            raise RuntimeError("Failed to parse CPU usage on Windows.") from e
    else:
        raise RuntimeError("Failed to retrieve CPU usage on Windows.")

def get_cpu_usage_unix():
    result = subprocess.run(['top', '-bn1', '-i', '0.1'], capture_output=True, text=True)
    if result.returncode == 0:
        lines = result.stdout.split('\n')
        for line in lines:
            if "%Cpu(s)" in line:
                try:
                    cpu_usage = line.split(',')[0].split()[1]
                    return float(cpu_usage)
                except (ValueError, IndexError) as e:
                    raise RuntimeError("Failed to parse CPU usage on Unix/Linux.") from e
    raise RuntimeError("Failed to retrieve CPU usage on Unix/Linux.")

