import json
import requests
import os
from datetime import datetime

def task_func(json_data, unknown_key, save_dir=None):
    try:
        data = json.loads(json_data)
    except json.JSONDecodeError as e:
        raise ValueError("Invalid JSON data.") from e

    url = data.get(unknown_key)
    if not url:
        raise KeyError(f"Key '{unknown_key}' not found in JSON data.")

    try:
        response = requests.get(url, timeout=10)
        response.raise_for_status()
    except requests.RequestException as e:
        raise ConnectionError(f"Failed to download file from {url}.") from e

    timestamp = datetime.now().strftime('%Y%m%d%H%M%S%f')
    filename = f"{unknown_key}_{timestamp}.txt"

    if save_dir:
        os.makedirs(save_dir, exist_ok=True)
        file_path = os.path.join(save_dir, filename)
    else:
        file_path = filename

    try:
        with open(file_path, 'wb') as file:
            file.write(response.content)
    except IOError as e:
        raise IOError(f"Failed to save file to {file_path}.") from e

    return os.path.abspath(file_path)
